import subprocess
import sys

def find_and_kill_process(process_name):
    try:
        # Find processes matching the given name
        result = subprocess.check_output(["pgrep", "-fl", process_name]).decode()
        processes = result.strip().split("\n")

        if not processes or processes == ['']:
            print("No matching processes found.")
            return

        print("Matching processes:")
        for i, process in enumerate(processes):
            print(f"{i + 1}. {process}")

        choice = input("Enter the number of the process to kill (or 'all' to kill all processes): ")

        if choice.lower() == 'all':
            for process in processes:
                pid = process.split()[0]
                subprocess.run(["kill", pid])
                print(f"Killed process {pid}")
        else:
            try:
                choice = int(choice) - 1
                if choice < 0 or choice >= len(processes):
                    print("Invalid choice.")
                else:
                    pid = processes[choice].split()[0]
                    subprocess.run(["kill", pid])
                    print(f"Killed process {pid}")
            except ValueError:
                print("Please enter a valid number or 'all'.")
    except subprocess.CalledProcessError as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    if len(sys.argv) != 2:
        print("Usage: python script.py <process_name>")
    else:
        find_and_kill_process(sys.argv[1])

